<?php require_once __DIR__.'/../includes/app-layout.php'; require_beyond_id(); $wallet=bos_page_start('Beyond Careers','Resume Center','Submit a resume for review.'); $message=''; if($_SERVER['REQUEST_METHOD']==='POST'){if(!bos_verify_csrf($_POST['csrf']??null)){$message='Security check failed.';}elseif(empty($_FILES['resume']['tmp_name'])){$message='Choose a resume file.';}else{$allowed=['application/pdf','application/vnd.openxmlformats-officedocument.wordprocessingml.document'];$mime=mime_content_type($_FILES['resume']['tmp_name'])?:'';if(!in_array($mime,$allowed,true)||$_FILES['resume']['size']>5*1024*1024){$message='Upload a PDF or DOCX up to 5 MB.';}else{$dir=__DIR__.'/uploads/resumes';if(!is_dir($dir))mkdir($dir,0750,true);$ext=$mime==='application/pdf'?'pdf':'docx';$name='resume_'.bos_current_user_id().'_'.date('Ymd_His').'.'.$ext;move_uploaded_file($_FILES['resume']['tmp_name'],$dir.'/'.$name);try{$s=beyond_db()->prepare("INSERT INTO resume_submissions(user_id,file_path,target_role,status,created_at) VALUES(?,?,?,'received',NOW())");$s->execute([bos_current_user_id(),'beyond-careers/uploads/resumes/'.$name,trim($_POST['target_role']??'')]);}catch(Throwable $e){};$admin=defined('ADMIN_EMAIL')?ADMIN_EMAIL:(defined('MAIL_FROM_ADDRESS')?MAIL_FROM_ADDRESS:'admin@beyondimagination.co.technology');@mail($admin,'New Beyond Careers resume submission','A new resume was submitted by user #'.bos_current_user_id().' for '.trim($_POST['target_role']??'unspecified role').'.');$message='Resume received and sent to the admin review queue.';}}} ?>
<main class="bos-main"><section class="bos-hero"><span class="bos-kicker">Beyond Careers</span><h1>Resume Center</h1><p>Upload your resume for review and connect it to your Beyond career profile.</p></section><section class="bos-section"><?php if($message):?><div class="bos-notice"><?=e($message)?></div><?php endif;?><form class="bos-form" method="post" enctype="multipart/form-data"><input type="hidden" name="csrf" value="<?=e(bos_csrf_token())?>"><label>Target role<input name="target_role" required placeholder="Frontend Developer"></label><label>Resume PDF or DOCX<input type="file" name="resume" required accept=".pdf,.docx"></label><button class="bos-btn">Submit resume</button></form></section></main><?php bos_page_end(); ?>
